const items = $input.all();

return items.flatMap(item => {
  if (!item.json.response) return [];
  const fixtureId = item.json.parameters?.fixture;

  return item.json.response
    .filter(event => (event.time?.elapsed ?? 0) >= 0)
    .map(event => ({
      json: {
        fixture_id:       fixtureId,
        minute:           event.time.elapsed,
        extra_time:       event.time.extra || null,
        team_external_id: event.team.id,
        team_name:        event.team?.name || null,
        player_id:        event.player?.id || null,
        player_name:      event.player?.name || null,
        assist_id:        event.assist?.id || null,
        assist_name:      event.assist?.name || null,
        type:             event.type,
        detail:           event.detail,
        comments:         event.comments || null
      }
    }));
});

// ── Hilfsfunktionen ─────────────────────────────────────
function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return `'${String(val).replace(/'/g, "''")}'`;
}
function num(val) {
  return (val === null || val === undefined) ? 'NULL' : val;
}
function getIcon(eventType) {
  const icons = {
    'goal':             '⚽',
    'own_goal':         '🙈',
    'yellow_card':      '🟨',
    'red_card':         '🟥',
    'yellow_red_card':  '🟨🟥',
    'substitution':     '🔄',
    'penalty_won':      '🎯',
    'penalty_cancelled':'❌',
    'goal_cancelled':   '🚫',
    'var_red_card':     '📺🟥',
    'missed_penalty':   '❌',
    'comment':          '💬',
  };
  return icons[eventType] || '📋';
}
function normalizeType(type, detail) {
  if (type === 'Card') {
    const d = (detail || '').toLowerCase();
    if (d.includes('red')) return 'red_card';
    return 'yellow_card';
  }
  if (type === 'Goal') {
    const d = (detail || '').toLowerCase();
    if (d.includes('own')) return 'own_goal';
    return 'goal';
  }
  if (type === 'Var') {
    const d = (detail || '').toLowerCase();
    if (d.includes('penalty confirmed'))  return 'penalty_won';
    if (d.includes('penalty cancelled')) return 'penalty_cancelled';
    if (d.includes('goal cancelled'))    return 'goal_cancelled';
    if (d.includes('red card'))          return 'var_red_card';
    return 'comment';
  }
  const TYPE_MAP = { 'subst': 'substitution', 'Miss': 'missed_penalty' };
  return TYPE_MAP[type] || 'comment';
}

// ── Schritt 1: Gelb-Rot erkennen ────────────────────────
const cardGroups = new Map();
const allItems = $input.all();

allItems.forEach((item, idx) => {
  const e = item.json;
  if (e.type !== 'Card') return;
  const key = `${e.fixture_id}_${e.minute}_${e.player_id ?? 'x'}`;
  if (!cardGroups.has(key)) cardGroups.set(key, []);
  cardGroups.get(key).push({ ...e, _idx: idx });
});

const yellowRedKeys = new Set();
const skipIdxs = new Set();

for (const [key, events] of cardGroups) {
  const hasYellow = events.some(e => (e.detail || '').toLowerCase().includes('yellow'));
  const hasRed    = events.some(e => (e.detail || '').toLowerCase().includes('red'));
  if (hasYellow && hasRed) {
    yellowRedKeys.add(key);
    events.forEach(e => skipIdxs.add(e._idx));
  }
}

// ── Schritt 2: Normale Events ────────────────────────────
const result = [];

allItems.forEach((item, idx) => {
  const e = item.json;
  if (skipIdxs.has(idx)) return;

  const eventType = normalizeType(e.type, e.detail);
  const sourceId  = `apifootball_${e.fixture_id}_${e.minute}_${e.type}_${(e.detail||'').replace(/\s+/g,'_')}_${e.player_id ?? 'x'}`;
  const description = JSON.stringify({
    player_id:   e.player_id,
    player_name: e.player_name,
    assist_id:   e.assist_id,
    assist_name: e.assist_name,
    team_id:     e.team_external_id,
    team_name:   e.team_name,
    type:        e.type,
    detail:      e.detail,
    comments:    e.comments,
    icon:        getIcon(eventType),
  });

  const query = `
    INSERT INTO events (
      match_id, time, time_additional,
      event_type, description, source, source_id, position
    )
    VALUES (
      (SELECT id FROM matches WHERE external_id = ${num(e.fixture_id)}::integer),
      ${num(e.minute)},
      ${num(e.extra_time)},
      ${esc(eventType)},
      ${esc(description)},
      'api_football',
      ${esc(sourceId)},
      ${num(e.minute)}
    )
    ON CONFLICT (source_id) WHERE source_id IS NOT NULL
    DO UPDATE SET source = EXCLUDED.source
    RETURNING id, event_type, time, description, (xmax = 0) AS is_new
  `.trim();

  result.push({ json: { query, fixture_id: e.fixture_id } });
});

// ── Schritt 3: Gelb-Rot-Events ───────────────────────────
for (const [key, events] of cardGroups) {
  if (!yellowRedKeys.has(key)) continue;

  const base = events[0];
  const sourceId = `apifootball_${base.fixture_id}_${base.minute}_yellowred_${base.player_id ?? 'x'}`;
  const description = JSON.stringify({
    player_id:   base.player_id,
    player_name: base.player_name,
    assist_id:   null,
    assist_name: null,
    team_id:     base.team_external_id,
    team_name:   base.team_name,
    type:        'Card',
    detail:      'Yellow Red Card',
    comments:    base.comments,
    icon:        '🟨🟥',
  });

  const query = `
    WITH cleanup AS (
      DELETE FROM events
      WHERE match_id = (SELECT id FROM matches WHERE external_id = ${num(base.fixture_id)}::integer)
        AND source = 'api_football'
        AND time = ${num(base.minute)}
        AND event_type IN ('yellow_card', 'red_card')
        AND (description::jsonb->>'player_id')::integer = ${num(base.player_id)}
    )
    INSERT INTO events (
      match_id, time, time_additional,
      event_type, description, source, source_id, position
    )
    VALUES (
      (SELECT id FROM matches WHERE external_id = ${num(base.fixture_id)}::integer),
      ${num(base.minute)},
      ${num(base.extra_time)},
      'yellow_red_card',
      ${esc(description)},
      'api_football',
      ${esc(sourceId)},
      ${num(base.minute)}
    )
    ON CONFLICT (source_id) WHERE source_id IS NOT NULL
    DO UPDATE SET source = EXCLUDED.source
    RETURNING id, event_type, time, description, (xmax = 0) AS is_new
  `.trim();

  result.push({ json: { query, fixture_id: base.fixture_id } });
}

return result;

function esc(v) {
  return `'${String(v).replace(/'/g, "''")}'`;
}

return $input.all().flatMap(item => {
  const e = item.json;
  const desc = typeof e.description === 'string'
    ? JSON.parse(e.description)
    : (e.description ?? {});

  const teamName = (desc.team_name || '').toLowerCase();
  if (!teamName.includes('frankfurt')) return [];

  const playerName = desc.player_name;
  if (!playerName) return [];

  const parts = playerName.trim().split(/\s+/);
  const lastName = parts[parts.length - 1];
  const eventTime = e.time ?? null;

  const query = `
    SELECT video_url, display_name, ${eventTime !== null ? eventTime : 'NULL'} AS event_time
    FROM players
    WHERE video_url IS NOT NULL
      AND team_id IN (SELECT id FROM teams WHERE name ILIKE '%Frankfurt%')
      AND (
        display_name ILIKE ${esc('%' + lastName + '%')}
        OR display_name ILIKE ${esc('%' + playerName + '%')}
      )
    LIMIT 1
  `.trim();

  return [{ json: { query, player_name: playerName, event_id: e.id, event_time: eventTime } }];
});

