const fixture = $json.response?.[0];
if (!fixture) return [];

const penHome = fixture.score?.penalty?.home ?? null;
const penAway = fixture.score?.penalty?.away ?? null;
if (penHome === null || penAway === null) return [];

const matchId = $('DB: Match-Instanz7').first().json.match_id;
const instance = $('DB: Match-Instanz7').first().json.instance || 'generic';
const tickerMode = $('DB: Match-Instanz7').first().json.ticker_mode ?? 'coop';
const homeTeamName = fixture.teams?.home?.name ?? 'Heim';
const awayTeamName = fixture.teams?.away?.name ?? 'Gast';
const winner = penHome > penAway ? homeTeamName : awayTeamName;

return [{ json: {
  match_id: matchId,
  penalty_home: penHome,
  penalty_away: penAway,
  instance,
  ticker_mode: tickerMode,
  text: `🥅 Elferschießen: ${winner} gewinnt ${penHome}:${penAway} n.E.`
} }];
